const dataset = [{
        team: "Alpha Squad",
        project: "UserAuth Service",
        stage: "PRD Definition",
        metric: "Requirements Clarity Score",
        value: 7.2,
        unit: "score",
        thresholdGood: 8.0,
        thresholdPoor: 5.0,
