    },
    {
        team: "Beta Team",
        project: "Payment Gateway",
        stage: "Tech Design",
        metric: "Design Review Duration",
        value: 8,
        unit: "days",
        thresholdGood: 5,
        thresholdPoor: 10,
        status: "Warning"
    },
    {
        team: "Beta Team",
        project: "Payment Gateway",
        stage: "Coding",
        metric: "Code Coverage Percentage",
        value: 78,
        unit: "percentage",
        thresholdGood: 85,
        thresholdPoor: 70,
        status: "Warning"
    },
    {
        team: "Gamma Engineers",
        project: "Analytics Dashboard",
        stage: "PR Review",
        metric: "Average PR Review Time",
        value: 4.5,
        unit: "days",
        thresholdGood: 2,
        thresholdPoor: 5,
        status: "Warning"
    },
    {
        team: "Gamma Engineers",
        project: "Analytics Dashboard",
        stage: "Integration Testing",
        metric: "Test Case Pass Rate",
        value: 92,
        unit: "percentage",
        thresholdGood: 90,
        thresholdPoor: 70,
        status: "Good"
    },
    {
        team: "Delta Force",
        project: "Mobile App V2",
        stage: "Functional Testing",
        metric: "Defect Density",
        value: 2.3,
        unit: "defects per kloc",
        thresholdGood: 1.5,
        thresholdPoor: 3.0,
        status: "Good"
    },
    {
        team: "Delta Force",
        project: "Mobile App V2",
        stage: "Perf Testing",
        metric: "Response Time P95",
        value: 180,
        unit: "milliseconds",
        thresholdGood: 200,
        thresholdPoor: 500,
        status: "Good"
    },
    {
        team: "Epsilon Squad",
        project: "API Refactor",
        stage: "Ready To Release",
        metric: "Rollback Risk Score",
        value: 6.8,
        unit: "score",
        thresholdGood: 4.0,
        thresholdPoor: 7.0,
        status: "Poor"
    },
    {
        team: "Alpha Squad",
        project: "Notification System",
        stage: "Coding",
        metric: "Technical Debt Ratio",
        value: 28,
        unit: "percentage",
        thresholdGood: 15,
        thresholdPoor: 25,
        status: "Poor"
    },
];

// Extract inputs from webhook body
const teamName = $input.first().json.body.team_name;
const sdlcStage = $input.first().json.body.current_sdlc_stage;

if (!teamName || !sdlcStage) {
    throw new Error("Missing required inputs: team_name and current_sdlc_stage");
}

// Filter matching records
const matches = dataset.filter(
    r => r.team.toLowerCase() === teamName.toLowerCase() &&
    r.stage.toLowerCase() === sdlcStage.toLowerCase()
);

// Determine overall severity
let overallStatus = "Good";
if (matches.some(r => r.status === "Poor")) overallStatus = "Poor";
else if (matches.some(r => r.status === "Warning")) overallStatus = "Warning";

return [{
    json: {
        teamName,
        sdlcStage,
        matches,
        overallStatus,
        hasRecords: matches.length > 0
    }
}];

const { teamName, sdlcStage, matches, hasRecords } = $input.first().json;
const timestamp = new Date().toISOString().replace("T", " ").slice(0, 19) + " UTC";

let message;

if (!hasRecords) {
  message = `
ℹ️ **PRE-FLIGHT CHECK — NO HISTORICAL DATA**
*Team:* ${teamName} | *Stage:* ${sdlcStage} | *Generated:* ${timestamp}

No historical records found for **${teamName}** at the **${sdlcStage}** stage.

This may be a new team or a new stage. Proceed with standard process diligence and ensure metrics are captured for future reference.
`.trim();
} else {
  const metricRows = matches.map(m =>
    `> ✅ **${m.metric}**: \`${m.value} ${m.unit}\``
  ).join("\n");

  message = `
✅ **PRE-FLIGHT CHECK — ALL CLEAR**
*Team:* ${teamName} | *Stage:* ${sdlcStage} | *Generated:* ${timestamp}

All historical metrics for this stage are within healthy thresholds. No blockers detected.

${metricRows}

You're good to proceed. Keep it up! 🚀
`.trim();
}

return [{ json: { message, status: "Good", teamName, sdlcStage } }];

const { teamName, sdlcStage, matches, overallStatus } = $input.first().json;

const statusEmoji = overallStatus === "Poor" ? "🚨" : "⚠️";
const statusLabel = overallStatus === "Poor" ? "CRITICAL" : "WARNING";
const timestamp = new Date().toISOString().replace("T", " ").slice(0, 19) + " UTC";

// Build the metric breakdown rows
const metricRows = matches.map(m => {
  const icon = m.status === "Poor" ? "🔴" : "🟡";
  return `> ${icon} **${m.metric}**: \`${m.value} ${m.unit}\` _(good: ${m.thresholdGood}, poor: ${m.thresholdPoor})_`;
}).join("\n");

// Remediation tips per stage
const remediationMap = {
  "coding": [
    "Run `coverage report` and add tests for uncovered branches before merging.",
    "Schedule a 30-min debt triage with the team to categorize and log items.",
    "Block PRs that push debt ratio above threshold using a pre-commit hook.",
  ],
  "prd definition": [
    "Conduct a structured requirements walkthrough with at least 2 stakeholders.",
    "Use a clarity scoring rubric — flag any requirement scoring below 7/10.",
    "Set a 48-hour freeze period before design handoff.",
  ],
  "prd review": [
    "Cap review cycles at 2 — escalate blockers to the product lead after cycle 2.",
    "Use async Loom reviews to reduce sync scheduling overhead.",
  ],
  "tech design": [
    "Time-box design reviews to 90 minutes with a structured agenda.",
    "Assign a design owner to drive decisions and prevent review sprawl.",
  ],
  "pr review": [
    "Enforce a 24-hour PR review SLA via CODEOWNERS.",
    "Break large PRs (>400 lines) into stacked smaller PRs.",
    "Use a PR checklist template to reduce back-and-forth cycles.",
  ],
  "ready to release": [
    "Validate rollback scripts in staging before cutting the release branch.",
    "Enable canary analysis in your deployment pipeline.",
    "Require a second approver sign-off if rollback risk score > 6.",
  ],
  "functional testing": [
    "Triage defect clusters by component — high-density areas need re-testing.",
    "Do not promote builds with defect density above threshold to staging.",
  ],
  "integration testing": [
    "Rerun the full regression suite if any new service dependencies were added.",
    "Add a flakiness check: flag tests with >5% failure rate for stabilization.",
  ],
};

const stageKey = sdlcStage.toLowerCase();
const tips = remediationMap[stageKey] || [
  "Review historical failure patterns for this stage.",
  "Align with the team lead before proceeding.",
  "Document any deviations from process in the sprint log.",
];

const remediationBlock = tips.map((t, i) => `${i + 1}. ${t}`).join("\n");

const message = `
${statusEmoji} **PRE-FLIGHT CHECKLIST — ${statusLabel}**
*Team:* ${teamName} | *Stage:* ${sdlcStage} | *Generated:* ${timestamp}

---

**Historical pitfalls detected for this stage:**

${metricRows}

---

**Recommended actions before proceeding:**

${remediationBlock}

---

> 🔁 This checklist was auto-generated from last quarter's metrics. Resolve flagged items or document mitigations in your sprint log before advancing.
`.trim();

return [{ json: { message, status: overallStatus, teamName, sdlcStage } }];
